import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"10、命运【X】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/10、命运【X】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/10、命运【X】.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/10、命运【X】.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_10、命运【x】",tabindex:"-1"},[s("10、命运【X】 "),e("a",{class:"header-anchor",href:"#_10、命运【x】","aria-label":'Permalink to "10、命运【X】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<h1 id="命运" tabindex="-1">命运 <a class="header-anchor" href="#命运" aria-label="Permalink to &quot;命运&quot;">​</a></h1><p>命运车轮</p><p>A+4800（替身价格）<br> 替身外貌：<br> 命运之轮是凭附在物体上的替身，命运之轮会绑定在车辆上，因此普通人同样也可以看到。替身为适应地形而改变汽车的特性，在改造和战斗时其外观会发生巨大变化，变成怪兽般的战车。<br> 替身数据：<br> 破坏力B 速度D（装甲防御） 射程D 持续力A 精密动作性E 成长性D<br> 替身对应主属性：智力<br> 替身能力：<br> 【车辆改造】：当替身使者驾驶一辆车辆时，能全方面改造所驾驶车辆，极大的提高车辆的性能和改变车辆的外观，在不改变外观情况下能为车辆增加【智力×55】移动速度/轮，提高车辆【智力】点装甲值，增加车辆【智力上附加成功数】点结构值，并且能具有仅针对该车辆生效的【智力上附加成功数】点快速修复（快速治疗），修复点（治疗点）上限为【智力上附加成功数×8】，在替身使者进行一次长休后恢复满值。<br> 人物使用迅捷动作改变外观后能使用车辆的任何东西作为武器，这种攻击方式射程为【智力×2】米，并且可以同时攻击多个目标，但是每次攻击都必须消耗一个标准动作，伤害类型视攻击方式决定为穿刺、钝击、切割。然后能使车辆拥有等于其移动速度的攀爬移动能力和遁地移动能力，其遁力为【智力上附加成功数×2】。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
